import { createElement, forwardRef } from "react";

export type LucideProps = React.SVGProps<SVGSVGElement> & {
  color?: string;
  size?: number | string;
  strokeWidth?: number | string;
};

type IconNode = Array<[string, Record<string, string>]>;

function createLucideIcon(iconNode: IconNode) {
  return forwardRef<SVGSVGElement, LucideProps>(({ color = "currentColor", size = 24, strokeWidth = 2, ...props }, ref) => (
    <svg
      ref={ref}
      xmlns="http://www.w3.org/2000/svg"
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke={color}
      strokeWidth={strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round"
      {...props}
    >
      {iconNode.map(([tag, attrs], i) => createElement(tag, { ...attrs, key: attrs.key ?? String(i) }))}
    </svg>
  ));
}

